INSERT INTO DOI_IVDD (YYYYMM, SEL_CODE, SITE, 자산처리계정, 품목자산분류, 재고자산종류, 매출원가계정, 대분류, 중분류, 소분류, 품목기타분류, 품명, 품번, 규격, 단위, 기초수량, 기초금액, 입고수량, 입고금액, 출고수량, 출고금액, 재고수량A, 결산재고수량B, 차이수량A_B, 재고금액C, 결산재고금액D, 차이금액C_D, 최종결산월재고단가, 생산수량, 생산금액, 구매수량, 구매금액, 적송입고수량, 적송입고금액, 기타입고수량, 기타입고금액, 판매수량, 판매원가, 투입수량, 투입금액, 적송출고수량, 적송출고금액, 기타출고수량, 기타출고금액)
SELECT YYYYMM, SEL_CODE, SITE, 자산처리계정, 품목자산분류, 재고자산종류, 매출원가계정, 대분류, 중분류, 소분류, 품목기타분류, 품명, 품번, 규격, 단위, 기초수량, 기초금액, 입고수량, 입고금액, 출고수량, 출고금액, 재고수량A, 결산재고수량B, 차이수량A_B, 재고금액C, 결산재고금액D, 차이금액C_D, 최종결산월재고단가, 생산수량, 생산금액, 구매수량, 구매금액, 적송입고수량, 적송입고금액, 기타입고수량, 기타입고금액, 판매수량, 판매원가, 투입수량, 투입금액, 적송출고수량, 적송출고금액, 기타출고수량, 기타출고금액
FROM (
SELECT *, MAX(seq_no) over (partition by YYYYMM, SEL_CODE, SITE, 품번, 품명) max_seq_no FROM #TempTable
) A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_IVDD b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SEL_CODE = a.SEL_CODE
	AND b.SITE = a.SITE
	AND b.품번 = a.품번
	AND b.품명 = a.품명
);

